enum DeviceIntegrityLevel {
  trusted,
  degraded,
  untrusted,
}

class DeviceIntegrityResult {
  final DeviceIntegrityLevel level;
  final List<String> failedChecks;
  final DateTime timestamp;
  final String checksum;

  DeviceIntegrityResult({
    required this.level,
    required this.failedChecks,
    required this.timestamp,
    required this.checksum,
  });

  bool get isTrusted => level == DeviceIntegrityLevel.trusted;
  bool get allowsFinancialTransactions =>
      level != DeviceIntegrityLevel.untrusted;
}

class DeviceIntegrityChecker {
  static const MethodChannel _channel =
      MethodChannel('com.payment.module/device_integrity');

  // Multiple independent checks for defense-in-depth
  static final List<IntegrityCheck> _checks = [
    RootJailbreakDetectionCheck(),
    DebuggerDetectionCheck(),
    EmulatorDetectionCheck(),
    TamperDetectionCheck(),
    AppSignatureCheck(),
    HookingFrameworkDetectionCheck(),
    FileSystemIntegrityCheck(),
    RuntimeIntegrityCheck(),
  ];

  /// Performs comprehensive device integrity verification using multiple
  /// independent checks. No single check determines the outcome.
  static Future<DeviceIntegrityResult> performFullIntegrityCheck() async {
    final List<String> failedChecks = [];
    int criticalFailures = 0;
    int warningFailures = 0;

    for (final check in _checks) {
      try {
        final result = await check.execute();
        if (!result.passed) {
          failedChecks.add(result.checkName);
          if (result.severity == CheckSeverity.critical) {
            criticalFailures++;
          } else {
            warningFailures++;
          }
        }
      } catch (e) {
        // A check that throws is treated as failed - fail secure
        failedChecks.add('${check.name}_error');
        warningFailures++;
      }
    }

    // Determine integrity level based on multiple factors
    DeviceIntegrityLevel level;
    if (criticalFailures >= 2) {
      level = DeviceIntegrityLevel.untrusted;
    } else if (criticalFailures >= 1 || warningFailures >= 3) {
      level = DeviceIntegrityLevel.degraded;
    } else if (warningFailures >= 1) {
      level = DeviceIntegrityLevel.degraded;
    } else {
      level = DeviceIntegrityLevel.trusted;
    }

    final timestamp = DateTime.now().toUtc();
    final checksumData =
        '${level.name}:${failedChecks.join(",")}:${timestamp.toIso8601String()}';
    final checksum = sha256.convert(utf8.encode(checksumData)).toString();

    return DeviceIntegrityResult(
      level: level,
      failedChecks: failedChecks,
      timestamp: timestamp,
      checksum: checksum,
    );
  }

  /// Verify the integrity result hasn't been tampered with
  static bool verifyResultIntegrity(DeviceIntegrityResult result) {
    final checksumData =
        '${result.level.name}:${result.failedChecks.join(",")}:${result.timestamp.toIso8601String()}';
    final expectedChecksum =
        sha256.convert(utf8.encode(checksumData)).toString();
    return result.checksum == expectedChecksum;
  }
}

