import 'dart:convert';
import 'dart:math';
import 'dart:typed_data';
import 'package:crypto/crypto.dart';

/// Secure storage wrapper that provides encrypted storage with
/// integrity verification. In production, use flutter_secure_storage
/// backed by Keychain (iOS) / Keystore (Android).
class SecurePaymentStorage {
  // In production, this would use flutter_secure_storage
  final Map<String, String> _store = {};
  final String _encryptionKey;

  SecurePaymentStorage._internal(this._encryptionKey);

  static SecurePaymentStorage? _instance;

  static Future<SecurePaymentStorage> getInstance() async {
    if (_instance == null) {
      // In production, derive key from secure hardware
      final key = _generateSecureKey();
      _instance = SecurePaymentStorage._internal(key);
    }
    return _instance!;
  }

  static String _generateSecureKey() {
    final random = Random.secure();
    final bytes = List<int>.generate(32, (_) => random.nextInt(256));
    return base64Encode(bytes);
  }

  Future<void> storeSecurely(String key, String value) async {
    final hmacValue = _computeHmac(key, value);
    final payload = jsonEncode({
      'value': value,
      'hmac': hmacValue,
      'timestamp': DateTime.now().toUtc().toIso8601String(),
    });
    // In production: await _secureStorage.write(key: key, value: payload);
    _store[key] = payload;
  }

  Future<String?> readSecurely(String key) async {
    // In production: final payload = await _secureStorage.read(key: key);
    final payload = _store[key];
    if (payload == null) return null;

    try {
      final data = jsonDecode(payload) as Map<String, dynamic>;
      final value = data['value'] as String;
      final storedHmac = data['hmac'] as String;

      // Verify integrity
      final expectedHmac = _computeHmac(key, value);
      if (storedHmac != expectedHmac) {
        // Data has been tampered with
        await deleteSecurely(key);
        return null;
      }

      return value;
    } catch (_) {
      return null;
    }
  }

  Future<void> deleteSecurely(String key) async {
    _store.remove(key);
  }

  String _computeHmac(String key, String value) {
    final hmacSha256 = Hmac(sha256, utf8.encode(_encryptionKey));
    return hmacSha256.convert(utf8.encode('$key:$value')).toString();
  }

  Future<void> clearAll() async {
    _store.clear();
  }
}


// lib/payment_module/models/payment_models.dart
import 'dart:convert';
import 'package:crypto/crypto.dart';

enum PaymentMethod {
  creditCard,
  debitCard,
  applePay,
  googlePay,
  inAppPurchase,
}

enum PaymentStatus {
  pending,
  processing,
  authorized,
  captured,
  completed,
  failed,
  cancelled,
  refunded,
  disputed,
}

enum TransactionType {
  purchase,
  subscription,
  consumable,
  nonConsumable,
}

class PaymentAmount {
  final int amountInCents; // Always store in smallest currency unit
  final String currency;

  const PaymentAmount({
    required this.amountInCents,
    required this.currency,
  });

  double get displayAmount => amountInCents / 100.0;

  Map<String, dynamic> toJson() => {
        'amount': amountInCents,
        'currency': currency,
      };

  factory PaymentAmount.fromJson(Map<String, dynamic> json) => PaymentAmount(
        amountInCents: json['amount'] as int,
        currency: json['currency'] as String,
      );
}

class PaymentRequest {
  final String requestId;
  final PaymentAmount amount;
  final PaymentMethod method;
  final TransactionType type;
  final String productId;
  final String? customerId;
  final Map<String, dynamic>? metadata;
  final DateTime createdAt;
  final String integrityHash;

  PaymentRequest({
    required this.requestId,
    required this.amount,
    required this.method,
    required this.type,
    required this.productId,
    this.customerId,
    this.metadata,
    DateTime? createdAt,
    String? integrityHash,
  })  : createdAt = createdAt ?? DateTime.now().toUtc(),
        integrityHash = integrityHash ??
            _computeIntegrityHash(
              requestId,
              amount,
              method,
              type,
              productId,
              customerId,
            );

  static String _computeIntegrityHash(
    String requestId,
    PaymentAmount amount,
    PaymentMethod method,
    TransactionType type,
    String productId,
    String? customerId,
  ) {
    final data =
        '$requestId:${amount.amountInCents}:${amount.currency}:${method.name}:${type.name}:$productId:${customerId ?? ""}';
    return sha256.convert(utf8.encode(data)).toString();
  }

  bool verifyIntegrity() {
    final expected = _computeIntegrityHash(
      requestId,
      amount,
      method,
      type,
      productId,
      customerId,
    );
    return integrityHash == expected;
  }

  Map<String, dynamic> toJson() => {
        'request_id': requestId,
        'amount': amount.toJson(),
        'method': method.name,
        'type': type.name,
        'product_id': productId,
        'customer_id': customerId,
        'metadata': metadata,
        'created_at': createdAt.toIso8601String(),
        'integrity_hash': integrityHash,
      };
}

class PaymentResult {
  final String transactionId;
  final String requestId;
  final PaymentStatus status;
  final PaymentAmount amount;
  final String? gatewayTransactionId;
  final String? receiptData;
  final String? errorMessage;
  final String? errorCode;
  final DateTime processedAt;
  final Map<String, dynamic>? metadata;

  const PaymentResult({
    required this.transactionId,
    required this.requestId,
    required this.status,
    required this.amount,
    this.gatewayTransactionId,
    this.receiptData,
    this.errorMessage,
    this.errorCode,
    required this.processedAt,
    this.metadata,
  });

  bool get isSuccessful =>
      status == PaymentStatus.completed || status == PaymentStatus.captured;

  Map<String, dynamic> toJson() => {
        'transaction_id': transactionId,
        'request_id': requestId,
        'status': status.name,
        'amount': amount.toJson(),
        'gateway_transaction_id': gatewayTransactionId,
        'receipt_data': receiptData,
        'error_message': errorMessage,
        'error_code': errorCode,
        'processed_at': processedAt.toIso8601String(),
        'metadata': metadata,
      };
}

class TokenizedCard {
  final String tokenId;
  final String last4;
  final String brand;
  final int expiryMonth;
  final int expiryYear;
  final DateTime tokenizedAt;

  const TokenizedCard({
    required this.tokenId,
    required this.last4,
    required this.brand,
    required this.expiryMonth,
    required this.expiryYear,
    required this.tokenizedAt,
  });

  bool get isExpired {
    final now = DateTime.now();
    return now.year > expiryYear ||
        (now.year == expiryYear && now.month > expiryMonth);
  }
}


