import 'dart:convert';
import 'dart:math';
import 'package:crypto/crypto.dart';

// Forward declarations for imports
import '../models/payment_models.dart';
import '../security/device_integrity_checker.dart';
import '../security/secure_storage.dart';

/// Abstract payment gateway interface for PCI-compliant payment processing.
/// Card data NEVER touches our servers - always tokenized client-side by the gateway SDK.
abstract class PaymentGateway {
  Future<PaymentResult> processPayment(PaymentRequest request);
  Future<TokenizedCard> tokenizeCard(Map<String, String> cardData);
  Future<PaymentResult> processWithToken(
      PaymentRequest request, String tokenId);
  Future<PaymentResult> refund(String transactionId, PaymentAmount amount);
  Future<bool> verifyReceipt(String receiptData);
}

/// Secure payment gateway implementation with defense-in-depth
class SecurePaymentGateway implements PaymentGateway {
  final String _apiKey;
  final String _merchantId;
  final String _baseUrl;
  final DeviceIntegrityChecker _integrityChecker = DeviceIntegrityChecker();

  // Rate limiting
  final Map<String, List<DateTime>> _requestTimestamps = {};
  static const int _maxRequestsPerMinute = 10;
  static const int _maxRequestsPerHour = 50;

  // Idempotency tracking
  final Map<String, PaymentResult> _processedRequests = {};

  SecurePaymentGateway({
    required String apiKey,
    required String merchantId,
    required String baseUrl,
  })  : _apiKey = apiKey,
        _merchantId = merchantId,
        _baseUrl = baseUrl;

  @override
  Future<PaymentResult> processPayment(PaymentRequest request) async {
    // Step 1: Verify request integrity
    if (!request.verifyIntegrity()) {
      return _createFailureResult(
        request.requestId,
        request.amount,
        'REQUEST_TAMPERED',
        'Payment request integrity verification failed',
      );
    }

    // Step 2: Check idempotency
    if (_processedRequests.containsKey(request.requestId)) {
      return _processedRequests[request.requestId]!;
    }

    // Step 3: Rate limiting
    if (!_checkRateLimit(request.customerId ?? 'anonymous')) {
      return _createFailureResult(
        request.requestId,
        request.amount,
        'RATE_LIMITED',
        'Too many payment requests. Please try again later.',
      );
    }

    // Step 4: Device integrity check - defense in depth
    final integrityResult =
        await DeviceIntegrityChecker.performFullIntegrityCheck();

    if (!DeviceIntegrityChecker.verifyResultIntegrity(integrityResult)) {
      return _createFailureResult(
        request.requestId,
        request.amount,
        'INTEGRITY_CHECK_TAMPERED',
        'Security verification failed',
      );
    }

    // Step 5: Apply security policy based on integrity level
    final securityPolicy =
        _determineSecurityPolicy(integrityResult, request.amount);

    if (securityPolicy == SecurityPolicy.block) {
      return _createFailureResult(
        request.requestId,
        request.amount,
        'DEVICE_UNTRUSTED',
        'Payment cannot be processed on this device due to security concerns. '
            'Please use a different device or contact support.',
      );
    }

    // Step 6: Apply additional protections for degraded devices
    if (securityPolicy == SecurityPolicy.enhanced) {
      // Require additional verification for degraded devices
      final additionalVerification =
          await _performEnhancedVerification(request);
      if (!additionalVerification) {
        return _createFailureResult(
          request.requestId,
          request.amount,
          'ENHANCED_VERIFICATION_FAILED',
          'Additional security verification required. Please verify your identity.',
        );
      }
    }

    // Step 7: Validate amount
    if (!_validateAmount(request.amount)) {
      return _createFailureResult(
        request.requestId,
        request.amount,
        'INVALID_AMOUNT',
        'Invalid payment amount',
      );
    }

    // Step 8: Process with gateway (server-side)
    final result = await _sendToGateway(request, integrityResult);

    // Step 9: Store result for idempotency
    _processedRequests[request.requestId] = result;

    // Step 10: Audit log
    await _auditLog(request, result, integrityResult);

    return result;
  }

  @override
  Future<TokenizedCard> tokenizeCard(Map<String, String> cardData) async {
    // CRITICAL: Card data is tokenized client-side by the payment gateway SDK
    // We NEVER store or transmit raw card numbers
    // This method delegates to the gateway's client-side tokenization

    // Validate card data format without storing it
    _validateCardDataFormat(cardData);

    // In production, this calls the gateway's tokenization API directly
    // The raw card data goes directly to the PCI-compliant gateway
    // and we only receive back a token

    // Simulated tokenization response
    final tokenId = _generateSecureToken();

    return TokenizedCard(
      tokenId: tokenId,
      last4: cardData['number']?.substring(cardData['number']!.length - 4) ??
          '****',
      brand: _detectCardBrand(cardData['number'] ?? ''),
      expiryMonth: int.tryParse(cardData['exp_month'] ?? '0') ?? 0,
      expiryYear: int.tryParse(cardData['exp_year'] ?? '0') ?? 0,
      tokenizedAt: DateTime.now().toUtc(),
    );
  }

  @override
  Future<PaymentResult> processWithToken(
      PaymentRequest request, String tokenId) async {
    // Process payment using a previously tokenized card
    // Token is sent to our server, which communicates with the gateway
    return processPayment(request);
  }

  @override
  Future<PaymentResult> refund(
      String transactionId, PaymentAmount amount) async {
    // Integrity check for refunds too
    final integrityResult =
        await DeviceIntegrityChecker.performFullIntegrityCheck();

    if (integrityResult.level == DeviceIntegrityLevel.untrusted) {
      return _createFailureResult(
        'refund_$transactionId',
        amount,
        'DEVICE_UNTRUSTED',
        'Refund cannot be processed on this device',
      );
    }

    // In production, send refund request to gateway via our server
    return PaymentResult(
      transactionId: 'ref_${_generateSecureToken()}',
      requestId: 'refund_$transactionId',
      status: PaymentStatus.refunded,
      amount: amount,
      processedAt: DateTime.now().toUtc(),
    );
  }

  @override
  Future<bool> verifyReceipt(String receiptData) async {
    // Server-side receipt verification
    // NEVER trust client-side receipt validation alone
    try {
      // In production, send receipt to our server which validates with
      // Apple/Google servers
      return true;
    } catch (e) {
      return false;
    }
  }

  // --- Private helper methods ---

  SecurityPolicy _determineSecurityPolicy(
      DeviceIntegrityResult integrity, PaymentAmount amount) {
    // Block untrusted devices for all financial transactions
    if (integrity.level == DeviceIntegrityLevel.untrusted) {
      return SecurityPolicy.block;
    }

    // Enhanced verification for degraded devices or high-value transactions
    if (integrity.level == DeviceIntegrityLevel.degraded) {
      return SecurityPolicy.enhanced;
    }

    // High-value transactions always get enhanced verification
    if (amount.amountInCents > 50000) {
      // > $500
      return SecurityPolicy.enhanced;
    }

    return SecurityPolicy.standard;
  }

  Future<bool> _performEnhancedVerification(PaymentRequest request) async {
    // In production, this would:
    // 1. Require biometric authentication
    // 2. Send OTP verification
    // 3. Require step-up authentication
    // 4. Apply stricter transaction limits
    // 5. Flag for manual review if needed

    // For now, simulate enhanced verification
    return true;
  }

  bool _checkRateLimit(String identifier) {
    final now = DateTime.now();
    final timestamps = _requestTimestamps[identifier] ?? [];

    // Clean old timestamps
    timestamps.removeWhere(
        (t) => now.difference(t).inHours > 1);

    // Check per-minute limit
    final recentMinute =
        timestamps.where((t) => now.difference(t).inMinutes < 1).length;
    if (recentMinute >= _maxRequestsPerMinute) return false;

    // Check per-hour limit
    if (timestamps.length >= _maxRequestsPerHour) return false;

    timestamps.add(now);
    _requestTimestamps[identifier] = timestamps;
    return true;
  }

  bool _validateAmount(PaymentAmount amount) {
    if (amount.amountInCents <= 0) return false;
    if (amount.amountInCents > 99999999) return false; // Max $999,999.99
    if (amount.currency.length != 3) return false;
    return true;
  }

  void _validateCardDataFormat(Map<String, String> cardData) {
    final number = cardData['number'] ?? '';
    if (number.length < 13 || number.length > 19) {
      throw PaymentValidationException('Invalid card number length');
    }

    // Luhn check
    if (!_luhnCheck(number)) {
      throw PaymentValidationException('Invalid card number');
    }

    final expMonth = int.tryParse(cardData['exp_month'] ?? '');
    final expYear = int.tryParse(cardData['exp_year'] ?? '');
    if (expMonth == null || expMonth < 1 || expMonth > 12) {
      throw PaymentValidationException('Invalid expiry month');
    }
    if (expYear == null || expYear < DateTime.now().year) {
      throw PaymentValidationException('Card expired');
    }

    final cvv = cardData['cvv'] ?? '';
    if (cvv.length < 3 || cvv.length > 4) {
      throw PaymentValidationException('Invalid CVV');
    }
  }

  bool _luhnCheck(String number) {
    int sum = 0;
    bool alternate = false;
    for (int i = number.length - 1; i >= 0; i--) {
      int digit = int.parse(number[i]);
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  String _detectCardBrand(String number) {
    if (number.startsWith('4')) return 'visa';
    if (number.startsWith('5')) return 'mastercard';
    if (number.startsWith('3')) return 'amex';
    if (number.startsWith('6')) return 'discover';
    return 'unknown';
  }

  String _generateSecureToken() {
    final random = Random.secure();
    final bytes = List<int>.generate(32, (_) => random.nextInt(256));
    return base64Url.encode(bytes).replaceAll('=', '');
  }

  Future<PaymentResult> _sendToGateway(
      PaymentRequest request, DeviceIntegrityResult integrity) async {
    // In production, this sends the payment request to our backend server
    // which then communicates with the payment gateway (Stripe, Braintree, etc.)
    //
    // The request includes:
    // - Payment details (amount, currency, token)
    // - Device integrity attestation
    // - Request signature
    // - Idempotency key

    try {
      // Build the server request with security context
      final serverRequest = {
        'payment': request.toJson(),
        'device_integrity': {
          'level': integrity.level.name,
          'failed_checks': integrity.failedChecks,
          'timestamp': integrity.timestamp.toIso8601String(),
          'checksum': integrity.checksum,
        },
        'request_signature': _signRequest(request),
      };

      // In production: final response = await _httpClient.post(...)
      // Simulated successful response
      return PaymentResult(
        transactionId: 'txn_${_generateSecureToken()}',
        requestId: request.requestId,
        status: PaymentStatus.completed,
        amount: request.amount,
        gatewayTransactionId: 'gw_${_generateSecureToken()}',
        processedAt: DateTime.now().toUtc(),
      );
    } catch (e) {
      return _createFailureResult(
        request.requestId,
        request.amount,
        'GATEWAY_ERROR',
        'Payment processing failed. Please try again.',
      );
    }
  }

  String _signRequest(PaymentRequest request) {
    final data = jsonEncode(request.toJson());
    final hmac = Hmac(sha256, utf8.encode(_apiKey));
    return hmac.convert(utf8.encode(data)).toString();
  }

  Future<void> _auditLog(
    PaymentRequest request,
    PaymentResult result,
    DeviceIntegrityResult integrity,
  ) async {
    // In production, send audit log to secure logging service
    final auditEntry = {
      'timestamp': DateTime.now().toUtc().toIso8601String(),
      'request_id': request.requestId,
      'transaction_id': result.transactionId,
      'status': result.status.name,
      'amount': request.amount.toJson(),
      'device_integrity_level': integrity.level.name,
      'failed_integrity_checks': integrity.failedChecks,
    };

    // Store locally for sync
    final storage = await SecurePaymentStorage.getInstance();
    await storage.storeSecurely(
      'audit_${request.requestId}',
      jsonEncode(auditEntry),
    );
  }

  PaymentResult _createFailureResult(
    String requestId,
    PaymentAmount amount,
    String errorCode,
    String errorMessage,
  ) {
    return PaymentResult(
      transactionId: 'failed_${_generateSecureToken()}',
      requestId: requestId,
      status: PaymentStatus.failed,
      amount: amount,
      errorCode: errorCode,
      errorMessage: errorMessage,
      processedAt: DateTime.now().toUtc(),
    );
  }
}

enum SecurityPolicy {
  standard,
  enhanced,
  block,
}

class PaymentValidationException implements Exception {
  final String message;
  PaymentValidationException(this.message);

  @override
  String toString() => 'PaymentValidationException: $message';
}


