/// Product catalog with server-verified pricing
class IAPProduct {
  final String productId;
  final String title;
  final String description;
  final PaymentAmount price;
  final TransactionType type;
  final bool isAvailable;

  const IAPProduct({
    required this.productId,
    required this.title,
    required this.description,
    required this.price,
    required this.type,
    this.isAvailable = true,
  });
}

/// Purchase record for tracking and verification
class PurchaseRecord {
  final String purchaseId;
  final String productId;
  final PaymentStatus status;
  final String? receiptData;
  final String? serverVerificationToken;
  final DateTime purchasedAt;
  final bool serverVerified;

  const PurchaseRecord({
    required this.purchaseId,
    required this.productId,
    required this.status,
    this.receiptData,
    this.serverVerificationToken,
    required this.purchasedAt,
    this.serverVerified = false,
  });

  Map<String, dynamic> toJson() => {
        'purchase_id': purchaseId,
        'product_id': productId,
        'status': status.name,
        'receipt_data': receiptData,
        'server_verification_token': serverVerificationToken,
        'purchased_at': purchasedAt.toIso8601String(),
        'server_verified': serverVerified,
      };

  factory PurchaseRecord.fromJson(Map<String, dynamic> json) => PurchaseRecord(
        purchaseId: json['purchase_id'] as String,
        productId: json['product_id'] as String,
        status: PaymentStatus.values.firstWhere(
          (s) => s.name == json['status'],
          orElse: () => PaymentStatus.failed,
        ),
        receiptData: json['receipt_data'] as String?,
        serverVerificationToken:
            json['server_verification_token'] as String?,
        purchasedAt: DateTime.parse(json['purchased_at'] as String),
        serverVerified: json['server_verified'] as bool? ?? false,
      );
}

/// Handles in-app purchases with server-side receipt verification
/// and device integrity checks
class InAppPurchaseHandler {
  final SecurePaymentGateway _gateway;
  final StreamController<PurchaseRecord> _purchaseStreamController =
      StreamController<PurchaseRecord>.broadcast();

  // Pending purchases awaiting verification
  final Map<String, PurchaseRecord> _pendingPurchases = {};

  // Verified purchases
  final Map<String, PurchaseRecord> _verifiedPurchases = {};

  Stream<PurchaseRecord> get purchaseStream =>
      _purchaseStreamController.stream;

  InAppPurchaseHandler({required SecurePaymentGateway gateway})
      : _gateway = gateway;

  /// Initialize the IAP handler and restore previous purchases
  Future<void> initialize() async {
    await _restorePurchases();
    // In production, also set up platform-specific purchase listeners
  }

  /// Fetch available products from the store
  Future<List<IAPProduct>> getAvailableProducts(
      List<String> productIds) async {
    // In production, query the App Store / Play Store
    // and cross-reference with server-side product catalog
    return [];
  }

  /// Initiate a purchase with full security checks
  Future<PurchaseRecord> purchaseProduct(String productId,
      {String? userId}) async {
    // Step 1: Device integrity check
    final integrityResult =
        await DeviceIntegrityChecker.performFullIntegrityCheck();

    if (integrityResult.level == DeviceIntegrityLevel.untrusted) {
      final record = PurchaseRecord(
        purchaseId: _generatePurchaseId(),
        productId: productId,
        status: PaymentStatus.failed,
        purchasedAt: DateTime.now().toUtc(),
      );
      _purchaseStreamController.add(record);
      throw PaymentSecurityException(
        'Purchase blocked due to device security concerns. '
        'Please use a trusted device.',
      );
    }

    // Step 2: For degraded devices, apply restrictions
    if (integrityResult.level == DeviceIntegrityLevel.degraded) {
      // Log the degraded state and apply transaction limits
      await _logSecurityEvent(
        'degraded_device_purchase',
        {'product_id': productId, 'user_id': userId},
      );
    }

    // Step 3: Create purchase record
    final purchaseId = _generatePurchaseId();
    final record = PurchaseRecord(
      purchaseId: purchaseId,
      productId: productId,
      status: PaymentStatus.pending,
      purchasedAt: DateTime.now().toUtc(),
    );

    _pendingPurchases[purchaseId] = record;
    _purchaseStreamController.add(record);

    // Step 4: Initiate platform purchase
    // In production, use in_app_purchase package
    try {
      final platformResult = await _initiatePlatformPurchase(productId);

      // Step 5: Server-side receipt verification (CRITICAL)
      final verifiedRecord = await _verifyPurchaseServerSide(
        purchaseId: purchaseId,
        productId: productId,
        receiptData: platformResult['receipt'] as String?,
        platform: platformResult['platform'] as String?,
      );

      _pendingPurchases.remove(purchaseId);
      _verifiedPurchases[purchaseId] = verifiedRecord;
      _purchaseStreamController.add(verifiedRecord);

      // Step 6: Persist verified purchase
      await _persistPurchase(verifiedRecord);

      return verifiedRecord;
    } catch (e) {
      final failedRecord = PurchaseRecord(
        purchaseId: purchaseId,
        productId: productId,
        status: PaymentStatus.failed,
        purchasedAt: DateTime.now().toUtc(),
      );
      _pendingPurchases.remove(purchaseId);
      _purchaseStreamController.add(failedRecord);
      rethrow;
    }
  }

  /// Verify a purchase receipt server-side
  /// NEVER trust client-side receipt validation for granting entitlements
  Future<PurchaseRecord> _verifyPurchaseServerSide({
    required String purchaseId,
    required String productId,
    String? receiptData,
    String? platform,
  }) async {
    if (receiptData == null) {
      return PurchaseRecord(
        purchaseId: purchaseId,
        productId: productId,
        status: PaymentStatus.failed,
        purchasedAt: DateTime.now().toUtc(),
        serverVerified: false,
      );
    }

    // In production, send receipt to YOUR server which then validates with:
    // - Apple: https://buy.itunes.apple.com/verifyReceipt
    // - Google: Google Play Developer API
    //
    // The server should:
    // 1. Validate receipt signature
    // 2. Check receipt hasn't been used before (replay protection)
    // 3. Verify product ID matches
    // 4. Verify price matches expected price
    // 5. Store the receipt for audit
    // 6. Return a server verification token

    final isValid = await _gateway.verifyReceipt(receiptData);

    if (isValid) {
      return PurchaseRecord(
        purchaseId: purchaseId,
        productId: productId,
        status: PaymentStatus.completed,
        receiptData: receiptData,
        serverVerificationToken: _generateVerificationToken(purchaseId),
        purchasedAt: DateTime.now().toUtc(),
        serverVerified: true,
      );
    } else {
      return PurchaseRecord(
        purchaseId: purchaseId,
        productId: productId,
        status: PaymentStatus.failed,
        receiptData: receiptData,
        purchasedAt: DateTime.now().toUtc(),
        serverVerified: false,
      );
    }
  }

  /// Check if a product has been purchased and verified
  Future<bool> hasValidPurchase(String productId) async {
    // Check in-memory cache first
    final cached = _verifiedPurchases.values
        .where((p) =>
            p.productId == productId &&
            p.status == PaymentStatus.completed &&
            p.serverVerified)
        .isNotEmpty;

    if (cached) return true;

    // Check persistent storage
    final storage = await SecurePaymentStorage.getInstance();
    final storedData =
        await storage.readSecurely('purchase_$productId');
    if (storedData != null) {
      try {
        final record =
            PurchaseRecord.fromJson(jsonDecode(storedData));
        if (record.serverVerified &&
            record.status == PaymentStatus.completed) {
          _verifiedPurchases[record.purchaseId] = record;
          return true;
        }
      } catch (_) {}
    }

    return false;
  }

  /// Restore purchases from platform and re-verify
  Future<List<PurchaseRecord>> _restorePurchases() async {
    // In production, query platform for previous purchases
    // and re-verify each one server-side
    final restoredPurchases = <PurchaseRecord>[];

    // Load from secure storage
    final storage = await SecurePaymentStorage.getInstance();
    // In production, iterate through stored purchases and verify

    return restoredPurchases;
  }

  Future<Map<String, dynamic>> _initiatePlatformPurchase(
      String productId) async {
    // In production, use in_app_purchase package
    // This is a placeholder
    return {
      'receipt': 'platform_receipt_data',
      'platform': 'ios', // or 'android'
    };
  }

  Future<void> _persistPurchase(PurchaseRecord record) async {
    final storage = await SecurePaymentStorage.getInstance();
    await storage.storeSecurely(
      'purchase_${record.productId}',
      jsonEncode(record.toJson()),
    );
  }

  String _generatePurchaseId() {
    final random = Random.secure();
    final bytes = List<int>.generate(16, (_) => random.nextInt(256));
    return 'pur_${base64Url.encode(bytes).replaceAll('=', '')}';
  }

  String _generateVerificationToken(String purchaseId) {
    final data = '$purchaseId:${DateTime.now().toUtc().toIso8601String()}';
    return sha256.convert(utf8.encode(data)).toString();
  }

  Future<void> _logSecurityEvent(
      String event, Map<String, dynamic> data) async {
    final storage = await SecurePaymentStorage.getInstance();
    final logEntry = {
      'event': event,
      'data': data,
      'timestamp': DateTime.now().toUtc().toIso8601String(),
    };
    await storage.storeSecurely(
      'security_log_${DateTime.now().millisecondsSinceEpoch}',
      jsonEncode(logEntry),
    );
  }

  void dispose() {
    _purchaseStreamController.close();
  }
}

class PaymentSecurityException implements Exception {
  final String message;
  PaymentSecurityException(this.message);

  @override
