}


// lib/payment_module/wallet/mobile_wallet_handler.dart
import 'dart:convert';
import 'dart:math';
import 'package:crypto/crypto.dart';

import '../models/payment_models.dart';
import '../security/device_integrity_checker.dart';
import '../gateway/payment_gateway.dart';

enum WalletType {
  applePay,
  googlePay,
}

class WalletPaymentRequest {
  final PaymentAmount amount;
  final String merchantName;
  final String countryCode;
  final List<String> supportedNetworks;
  final String? merchantIdentifier;

  const WalletPaymentRequest({
    required this.amount,
    required this.merchantName,
    required this.countryCode,
    this.supportedNetworks = const ['visa', 'mastercard', 'amex'],
    this.merchantIdentifier,
  });
}

/// Handles Apple Pay and Google Pay integration with security checks
class MobileWalletHandler {
  final SecurePaymentGateway _gateway;

  MobileWalletHandler({required SecurePaymentGateway gateway})
      : _gateway = gateway;

  /// Check if a wallet type is available on this device
  Future<bool> isWalletAvailable(WalletType type) async {
    // In production, check platform availability
    // Apple Pay: PKPaymentAuthorizationController.canMakePayments()
    // Google Pay: IsReadyToPayRequest
    return true;
  }

  /// Process a wallet payment with full security checks
  Future<PaymentResult> processWalletPayment({
    required WalletType walletType,
    required WalletPaymentRequest walletRequest,
    String? userId,
  }) async {
    // Step 1: Device integrity check
    final integrityResult =
        await DeviceIntegrityChecker.performFullIntegrityCheck();

    if (!DeviceIntegrityChecker.verifyResultIntegrity(integrityResult)) {
      throw PaymentSecurityException(
          'Security verification integrity check failed');
    }

    // Step 2: Apply security policy
    if (integrityResult.level == DeviceIntegrityLevel.untrusted) {
      throw PaymentSecurityException(
        'Wallet payment blocked due to device security concerns. '
        'Mobile wallet payments require a trusted device.',
      );
    }

    // Step 3: For degraded devices, apply additional restrictions
    if (integrityResult.level == DeviceIntegrityLevel.degraded) {
      // Apply lower transaction limits for degraded devices
      if (walletRequest.amount.amountInCents > 10000) {
        // $100 limit
        throw PaymentSecurityException(
          'Transaction amount exceeds the limit for this device. '
          'Please use a different payment method or device.',
        );
      }
    }

    // Step 4: Validate the wallet request
    _validateWalletRequest(walletRequest);

    // Step 5: Present wallet UI and get payment token
    final walletToken = await _presentWalletUI(walletType, walletRequest);

    if (walletToken == null) {
      return PaymentResult(
        transactionId: 'wallet_cancelled',
        requestId: _generateRequestId(),
        status: PaymentStatus.cancelled,
        amount: walletRequest.amount,
        processedAt: DateTime.now().toUtc(),
      );
    }

    // Step 6: Create payment request with wallet token
    final paymentRequest = PaymentRequest(
      requestId: _generateRequestId(),
      amount: walletRequest.amount,
      method: walletType == WalletType.applePay
          ? PaymentMethod.applePay
          : PaymentMethod.googlePay,
      type: TransactionType.purchase,
      productId: 'wallet_payment',
      customerId: userId,
      metadata: {
        'wallet_type': walletType.name,
        'wallet_token': walletToken,
        'device_integrity': integrityResult.level.name,
      },
    );

    // Step 7: Process through gateway
    return _gateway.processPayment(paymentRequest);
  }

  void _validateWalletRequest(WalletPaymentRequest request) {
    if (request.amount.amountInCents <= 0) {
      throw PaymentValidationException('Invalid payment amount');
    }
    if (request.merchantName.isEmpty) {
      throw PaymentValidationException('Merchant name is required');
    }
    if (request.countryCode.length != 2) {
      throw PaymentValidationException('Invalid country code');
    }
    if (request.supportedNetworks.isEmpty) {
      throw PaymentValidationException(
          'At least one payment network must be supported');
    }
  }

  Future<String?> _presentWalletUI(
      WalletType type, WalletPaymentRequest request) async {
    // In production, present the native wallet UI:
    // Apple Pay: PKPaymentAuthorizationViewController
    // Google Pay: PaymentsClient.loadPaymentData()
    //
    // The wallet provides a payment token that is sent to the gateway
    // We never see the actual card details

    // Simulated wallet token
    return 'wallet_token_${_generateSecureToken()}';
  }

  String _generateRequestId() {
    final random = Random.secure();
    final bytes = List<int>.generate(16, (_) => random.nextInt(256));
    return 'req_${base64Url.encode(bytes).replaceAll('=', '')}';
  }

  String _generateSecureToken() {
    final random = Random.secure();
    final bytes = List<int>.generate(32, (_) => random.nextInt(256));
    return base64Url.encode(bytes).replaceAll('=', '');
  }
}


// lib/payment_module/transaction/transaction_manager.dart
import 'dart:async';
import 'dart:convert';
import 'dart:math';

import '../models/payment_models.dart';
import '../security/device_integrity_checker.dart';
import '../security/secure_storage.dart';
import '../gateway/payment_gateway.dart';

enum TransactionState {
  initialized,
  integrityChecked,
  validated,
  submitted,
  confirmed,
  completed,
  failed,
  rolledBack,
}

class TransactionContext {
  final String transactionId;
  final PaymentRequest request;
  final DeviceIntegrityResult integrityResult;
  TransactionState state;
  PaymentResult? result;
  final List<TransactionEvent> events;
  final DateTime startedAt;

  TransactionContext({
    required this.transactionId,
    required this.request,
    required this.integrityResult,
    this.state = TransactionState.initialized,
    this.result,
    List<TransactionEvent>? events,
    DateTime? startedAt,
  })  : events = events ?? [],
        startedAt = startedAt ?? DateTime.now().toUtc();

  void addEvent(String event, {Map<String, dynamic>? data}) {
    events.add(TransactionEvent(
      event: event,
      timestamp: DateTime.now().toUtc(),
      data: data,
    ));
  }
}

class TransactionEvent {
  final String event;
  final DateTime timestamp;
  final Map<String, dynamic>? data;

  const TransactionEvent({
    required this.event,
    required this.timestamp,
    this.data,
  });

  Map<String, dynamic> toJson() => {
        'event': event,
        'timestamp': timestamp.toIso8601String(),
        'data': data,
      };
}

/// Manages the full lifecycle of payment transactions with
/// state machine, retry logic, and comprehensive audit trail
class TransactionManager {
  final SecurePaymentGateway _gateway;
  final Map<String, TransactionContext> _activeTransactions = {};
  final StreamController<TransactionContext> _transactionStream =
      StreamController<TransactionContext>.broadcast();

  static const int _maxRetries = 3;
  static const Duration _retryDelay = Duration(seconds: 2);
  static const Duration _transactionTimeout = Duration(minutes: 5);

  Stream<TransactionContext> get transactionStream =>
      _transactionStream.stream;

  TransactionManager({required SecurePaymentGateway gateway})
      : _gateway = gateway;

  /// Execute a payment transaction with full lifecycle management
  Future<PaymentResult> executeTransaction(PaymentRequest request) async {
    // Step 1: Device integrity check
    final integrityResult =
        await DeviceIntegrityChecker.performFullIntegrityCheck();

    // Step 2: Create transaction context
    final context = TransactionContext(
      transactionId: _generateTransactionId(),
      request: request,
      integrityResult: integrityResult,
    );

    _activeTransactions[context.transactionId] = context;
    context.addEvent('transaction_created');
    _transactionStream.add(context);

    try {
      // Step 3: Integrity gate
      context.state = TransactionState.integrityChecked;
      context.addEvent('integrity_checked', data: {
        'level': integrityResult.level.name,
        'failed_checks': integrityResult.failedChecks,
      });

      if (integrityResult.level == DeviceIntegrityLevel.untrusted) {
        context.state = TransactionState.failed;
        context.addEvent('blocked_untrusted_device');
        final failResult = PaymentResult(
          transactionId: context.transactionId,
          requestId: request.requestId,
          status: PaymentStatus.failed,
          amount: request.amount,
          errorCode: 'DEVICE_UNTRUSTED',
          errorMessage: 'Transaction blocked: untrusted device',
          processedAt: DateTime.now().toUtc(),
        );
        context.result = failResult;
        await _persistTransactionRecord(context);
        return failResult;
      }

      // Step 4: Validate request
      context.state = TransactionState.validated;
      context.addEvent('request_validated');

      if (!request.verifyIntegrity()) {
        throw PaymentSecurityException('Request integrity check failed');
      }

      // Step 5: Submit to gateway with retry logic
      context.state = TransactionState.submitted;
      context.addEvent('submitted_to_gateway');

      PaymentResult? result;
      int retryCount = 0;

      while (retryCount < _maxRetries) {
        try {
          result = await _gateway
              .processPayment(request)
              .timeout(_transactionTimeout);

          if (result.isSuccessful ||
              result.status == PaymentStatus.failed) {
            break; // Don't retry on definitive success or failure
          }
        } catch (e) {
          retryCount++;
          context.addEvent('retry_attempt', data: {
            'attempt': retryCount,
            'error': e.toString(),
          });

          if (retryCount >= _maxRetries) {
            result = PaymentResult(
              transactionId: context.transactionId,
              requestId: request.requestId,
              status: PaymentStatus.failed,
              amount: request.amount,
              errorCode: 'MAX_RETRIES_EXCEEDED',
              errorMessage: 'Payment failed after $retryCount attempts',
              processedAt: DateTime.now().toUtc(),
            );
            break;
          }

          // Exponential backoff
          await Future.delayed(_retryDelay * retryCount);
        }
      }

